import{_ as o,o as a,c as t,ag as s}from"./chunks/framework.CTpQozEL.js";const m=JSON.parse('{"title":"시스템 프롬프트","description":"OpenClaw 시스템 프롬프트가 포함하는 것과 조합 방법","frontmatter":{"title":"시스템 프롬프트","description":"OpenClaw 시스템 프롬프트가 포함하는 것과 조합 방법"},"headers":[],"relativePath":"concepts/system-prompt.md","filePath":"concepts/system-prompt.md","lastUpdated":null}'),c={name:"concepts/system-prompt.md"};function n(l,e,d,p,r,i){return a(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="시스템-프롬프트" tabindex="-1">시스템 프롬프트 <a class="header-anchor" href="#시스템-프롬프트" aria-label="Permalink to &quot;시스템 프롬프트&quot;">​</a></h1><p>OpenClaw는 모든 에이전트 실행에 대해 커스텀 시스템 프롬프트를 구축합니다. 이 프롬프트는 <strong>OpenClaw 소유</strong>이며 pi-coding-agent 기본 프롬프트를 사용하지 않습니다.</p><p>프롬프트는 OpenClaw가 조합하여 각 에이전트 실행에 주입합니다.</p><p>프로바이더 플러그인은 전체 OpenClaw 소유 프롬프트를 대체하지 않고 캐시 인식 프롬프트 지침을 기여할 수 있습니다. 프로바이더 런타임은 다음을 할 수 있습니다:</p><ul><li>소규모 명명된 코어 섹션 세트 교체 (<code>interaction_style</code>, <code>tool_call_style</code>, <code>execution_bias</code>)</li><li>프롬프트 캐시 경계 위에 <strong>안정적인 접두사</strong> 주입</li><li>프롬프트 캐시 경계 아래에 <strong>동적 접미사</strong> 주입</li></ul><p>모델 패밀리별 튜닝에는 프로바이더 소유 기여를 사용하십시오. 일반적인 프로바이더 동작이 아닌 호환성 또는 진정으로 전역적인 프롬프트 변경에는 레거시 <code>before_prompt_build</code> 프롬프트 변환을 유지하십시오.</p><h2 id="구조" tabindex="-1">구조 <a class="header-anchor" href="#구조" aria-label="Permalink to &quot;구조&quot;">​</a></h2><p>프롬프트는 의도적으로 간결하며 고정된 섹션을 사용합니다:</p><ul><li><strong>툴링</strong>: 구조화된 도구 진실의 원천 알림 + 런타임 도구 사용 지침.</li><li><strong>안전성</strong>: 권력 추구 동작 또는 감독 우회를 피하기 위한 짧은 가드레일 알림.</li><li><strong>스킬</strong> (사용 가능한 경우): 모델에게 필요 시 스킬 지침을 로드하는 방법을 알려줍니다.</li><li><strong>OpenClaw 자체 업데이트</strong>: <code>config.schema.lookup</code>으로 안전하게 구성 검사, <code>config.patch</code>로 구성 패치, <code>config.apply</code>로 전체 구성 교체, 명시적 사용자 요청 시에만 <code>update.run</code> 실행. 소유자 전용 <code>gateway</code> 도구는 <code>tools.exec.ask</code> / <code>tools.exec.security</code> 재작성도 거부합니다. 이는 보호된 exec 경로로 정규화되는 레거시 <code>tools.bash.*</code> 별칭 포함.</li><li><strong>워크스페이스</strong>: 작업 디렉터리 (<code>agents.defaults.workspace</code>).</li><li><strong>문서</strong>: OpenClaw 문서의 로컬 경로 (리포 또는 npm 패키지)와 언제 읽어야 하는지.</li><li><strong>워크스페이스 파일 (주입됨)</strong>: 아래에 부트스트랩 파일이 포함됨을 나타냄.</li><li><strong>샌드박스</strong> (활성화된 경우): 샌드박싱된 런타임, 샌드박스 경로, 상승된 exec 사용 가능 여부를 나타냄.</li><li><strong>현재 날짜 및 시간</strong>: 사용자 로컬 시간, 타임존, 시간 형식.</li><li><strong>응답 태그</strong>: 지원되는 프로바이더를 위한 선택적 응답 태그 구문.</li><li><strong>하트비트</strong>: 기본 에이전트에 대해 하트비트가 활성화된 경우, 하트비트 프롬프트 및 ack 동작.</li><li><strong>런타임</strong>: 호스트, OS, node, 모델, 리포 루트 (감지된 경우), thinking 레벨 (한 줄).</li><li><strong>추론</strong>: 현재 가시성 레벨 + /reasoning 토글 힌트.</li></ul><p>툴링 섹션에는 장기 실행 작업을 위한 런타임 지침도 포함됩니다:</p><ul><li><code>exec</code> sleep 루프, <code>yieldMs</code> 지연 트릭, 반복 <code>process</code> 폴링 대신 향후 후속 조치를 위해 cron 사용 (<code>나중에 다시 확인</code>, 알림, 반복 작업)</li><li>지금 시작하고 백그라운드에서 계속 실행되는 커맨드에만 <code>exec</code> / <code>process</code> 사용</li><li>자동 완료 웨이크가 활성화된 경우, 커맨드를 한 번 시작하고 출력을 내보내거나 실패할 때 푸시 기반 웨이크 경로에 의존</li><li>실행 중인 커맨드를 검사해야 할 때 로그, 상태, 입력, 개입에 <code>process</code> 사용</li><li>태스크가 더 크다면 <code>sessions_spawn</code> 선호. 서브 에이전트 완료는 푸시 기반이며 요청자에게 자동 공지</li><li>완료를 기다리기 위해 루프에서 <code>subagents list</code> / <code>sessions_list</code> 폴링하지 않음</li></ul><p>실험적 <code>update_plan</code> 도구가 활성화된 경우, 툴링은 또한 모델에게 사소하지 않은 멀티 스텝 작업에만 사용하고, 정확히 하나의 <code>in_progress</code> 단계를 유지하며, 각 업데이트 후 전체 계획을 반복하지 않도록 알려줍니다.</p><p>시스템 프롬프트의 안전성 가드레일은 권고적입니다. 모델 동작을 안내하지만 정책을 강제하지는 않습니다. 하드 강제에는 도구 정책, exec 승인, 샌드박싱, 채널 허용 목록을 사용하십시오. 운영자는 설계상 이를 비활성화할 수 있습니다.</p><p>네이티브 승인 카드/버튼이 있는 채널에서 런타임 프롬프트는 이제 에이전트에게 해당 네이티브 승인 UI를 먼저 의존하도록 알립니다. 도구 결과가 채팅 승인을 사용할 수 없거나 수동 승인이 유일한 경로라고 말할 때만 수동 <code>/approve</code> 커맨드를 포함해야 합니다.</p><h2 id="프롬프트-모드" tabindex="-1">프롬프트 모드 <a class="header-anchor" href="#프롬프트-모드" aria-label="Permalink to &quot;프롬프트 모드&quot;">​</a></h2><p>OpenClaw는 서브 에이전트에 대해 더 작은 시스템 프롬프트를 렌더링할 수 있습니다. 런타임은 각 실행에 대해 <code>promptMode</code>를 설정합니다 (사용자 대면 구성이 아님):</p><ul><li><code>full</code> (기본값): 위의 모든 섹션 포함.</li><li><code>minimal</code>: 서브 에이전트에 사용됨. <strong>스킬</strong>, <strong>메모리 회상</strong>, <strong>OpenClaw 자체 업데이트</strong>, <strong>모델 별칭</strong>, <strong>사용자 ID</strong>, <strong>응답 태그</strong>, <strong>메시징</strong>, <strong>자동 응답</strong>, <strong>하트비트</strong> 생략. 툴링, <strong>안전성</strong>, 워크스페이스, 샌드박스, 현재 날짜 및 시간 (알 수 있는 경우), 런타임, 주입된 컨텍스트는 계속 사용 가능.</li><li><code>none</code>: 기본 ID 줄만 반환합니다.</li></ul><p><code>promptMode=minimal</code>인 경우, 추가 주입된 프롬프트는 <strong>그룹 채팅 컨텍스트</strong> 대신 <strong>서브에이전트 컨텍스트</strong>로 레이블이 지정됩니다.</p><h2 id="워크스페이스-부트스트랩-주입" tabindex="-1">워크스페이스 부트스트랩 주입 <a class="header-anchor" href="#워크스페이스-부트스트랩-주입" aria-label="Permalink to &quot;워크스페이스 부트스트랩 주입&quot;">​</a></h2><p>부트스트랩 파일은 <strong>프로젝트 컨텍스트</strong> 아래에 정리되고 추가되므로 모델은 명시적 읽기 없이 ID 및 프로필 컨텍스트를 볼 수 있습니다:</p><ul><li><code>AGENTS.md</code></li><li><code>SOUL.md</code></li><li><code>TOOLS.md</code></li><li><code>IDENTITY.md</code></li><li><code>USER.md</code></li><li><code>HEARTBEAT.md</code></li><li><code>BOOTSTRAP.md</code> (새 워크스페이스에서만)</li><li><code>MEMORY.md</code> (있는 경우), 없으면 소문자 폴백 <code>memory.md</code></li></ul><p>이 파일들은 모두 파일별 게이트가 적용되지 않는 한 모든 턴에서 <strong>컨텍스트 창에 주입</strong>됩니다. <code>HEARTBEAT.md</code>는 기본 에이전트에 대해 하트비트가 비활성화되거나 <code>agents.defaults.heartbeat.includeSystemPromptSection</code>이 false인 경우 일반 실행에서 생략됩니다. 주입된 파일을 간결하게 유지하십시오 -- 특히 시간이 지남에 따라 성장할 수 있고 예상치 못하게 높은 컨텍스트 사용 및 더 잦은 컴팩션으로 이어질 수 있는 <code>MEMORY.md</code>.</p><blockquote><p><strong>참고:</strong> <code>memory/*.md</code> 일별 파일은 자동으로 주입되지 <strong>않습니다</strong>. <code>memory_search</code> 및 <code>memory_get</code> 도구를 통해 요청 시 접근하므로 모델이 명시적으로 읽지 않는 한 컨텍스트 창에 포함되지 않습니다.</p></blockquote><p>큰 파일은 마커로 잘립니다. 파일당 최대 크기는 <code>agents.defaults.bootstrapMaxChars</code> (기본값: 20000)로 제어됩니다. 파일 전체에서 주입된 부트스트랩 콘텐츠의 합계는 <code>agents.defaults.bootstrapTotalMaxChars</code> (기본값: 150000)로 제한됩니다. 누락된 파일은 짧은 파일 누락 마커를 주입합니다. 잘림이 발생하면 OpenClaw는 프로젝트 컨텍스트에 경고 블록을 주입할 수 있습니다. <code>agents.defaults.bootstrapPromptTruncationWarning</code> (<code>off</code>, <code>once</code>, <code>always</code>; 기본값: <code>once</code>)으로 제어하십시오.</p><p>서브 에이전트 세션은 <code>AGENTS.md</code> 및 <code>TOOLS.md</code>만 주입합니다 (다른 부트스트랩 파일은 서브 에이전트 컨텍스트를 작게 유지하기 위해 필터링됨).</p><p>내부 훅은 <code>agent:bootstrap</code>을 통해 이 단계를 가로채 주입된 부트스트랩 파일을 변환하거나 교체할 수 있습니다 (예: <code>SOUL.md</code>를 대체 페르소나로 교체).</p><p>에이전트가 덜 일반적으로 들리기를 원한다면 <a href="/openclaw-docs-ko/concepts/soul">SOUL.md 개성 가이드</a>로 시작하십시오.</p><p>각 주입된 파일이 얼마나 기여하는지 검사하려면 (원시 대 주입, 잘림, 도구 스키마 오버헤드 포함) <code>/context list</code> 또는 <code>/context detail</code>을 사용하십시오. <a href="/openclaw-docs-ko/concepts/context">컨텍스트</a>를 참조하십시오.</p><h2 id="시간-처리" tabindex="-1">시간 처리 <a class="header-anchor" href="#시간-처리" aria-label="Permalink to &quot;시간 처리&quot;">​</a></h2><p>사용자 타임존이 알려진 경우, 시스템 프롬프트에는 전용 <strong>현재 날짜 및 시간</strong> 섹션이 포함됩니다. 프롬프트 캐시를 안정적으로 유지하기 위해 이제 <strong>타임존</strong>만 포함합니다 (동적 시계나 시간 형식 없음).</p><p>에이전트가 현재 시간이 필요한 경우 <code>session_status</code>를 사용하십시오. 상태 카드에는 타임스탬프 줄이 포함됩니다. 동일한 도구는 선택적으로 세션별 모델 오버라이드를 설정할 수 있습니다 (<code>model=default</code>는 초기화).</p><p>다음으로 구성하십시오:</p><ul><li><code>agents.defaults.userTimezone</code></li><li><code>agents.defaults.timeFormat</code> (<code>auto</code> | <code>12</code> | <code>24</code>)</li></ul><p>전체 동작 세부사항은 <a href="/openclaw-docs-ko/date-time">날짜 및 시간</a>을 참조하십시오.</p><h2 id="스킬" tabindex="-1">스킬 <a class="header-anchor" href="#스킬" aria-label="Permalink to &quot;스킬&quot;">​</a></h2><p>적격한 스킬이 있는 경우, OpenClaw는 각 스킬의 <strong>파일 경로</strong>를 포함하는 간결한 <strong>사용 가능한 스킬 목록</strong> (<code>formatSkillsForPrompt</code>)을 주입합니다. 프롬프트는 모델에게 나열된 위치 (워크스페이스, 관리됨, 또는 번들됨)에서 <code>read</code>를 사용하여 SKILL.md를 로드하도록 지시합니다. 적격한 스킬이 없으면 스킬 섹션이 생략됩니다.</p><p>적격성에는 스킬 메타데이터 게이트, 런타임 환경/구성 확인, <code>agents.defaults.skills</code> 또는 <code>agents.list[].skills</code>가 구성된 경우 유효한 에이전트 스킬 허용 목록이 포함됩니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&amp;lt;available_skills&amp;gt;</span></span>
<span class="line"><span>  &amp;lt;skill&amp;gt;</span></span>
<span class="line"><span>    &amp;lt;name&amp;gt;...&amp;lt;/name&amp;gt;</span></span>
<span class="line"><span>    &amp;lt;description&amp;gt;...&amp;lt;/description&amp;gt;</span></span>
<span class="line"><span>    &amp;lt;location&amp;gt;...&amp;lt;/location&amp;gt;</span></span>
<span class="line"><span>  &amp;lt;/skill&amp;gt;</span></span>
<span class="line"><span>&amp;lt;/available_skills&amp;gt;</span></span></code></pre></div><p>이는 여전히 대상 스킬 사용을 활성화하면서 기본 프롬프트를 작게 유지합니다.</p><h2 id="문서" tabindex="-1">문서 <a class="header-anchor" href="#문서" aria-label="Permalink to &quot;문서&quot;">​</a></h2><p>사용 가능한 경우, 시스템 프롬프트에는 로컬 OpenClaw 문서 디렉터리 (리포 워크스페이스의 <code>docs/</code> 또는 번들된 npm 패키지 문서)를 가리키는 <strong>문서</strong> 섹션이 포함됩니다. 또한 공개 미러, 소스 리포, 커뮤니티 Discord, 스킬 탐색을 위한 ClawHub (<a href="https://clawhub.ai" target="_blank" rel="noreferrer">https://clawhub.ai</a>)도 언급합니다. 프롬프트는 모델에게 OpenClaw 동작, 커맨드, 구성, 아키텍처에 대해 먼저 로컬 문서를 참조하도록 지시하며, 가능하면 직접 <code>openclaw status</code>를 실행하도록 합니다 (접근이 없는 경우에만 사용자에게 문의).</p>`,41)])])}const u=o(c,[["render",n]]);export{m as __pageData,u as default};
